INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-d35ec6db-moex-00437', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲以優厚報酬延請乙為其建造A屋，作為新婚處所，雙方並約定由甲自行提供建屋所需之全部材 料。下列敘述，何者錯誤？', '["若新造之A屋有數面牆面的油漆輕微不均，則甲不得解除契約", "若因乙之設計不當，致新造之A屋異常歪斜，經專業機構鑑定認有實質上之倒塌危險，則甲仍 不得解除契約", "若甲於A屋交付後第2年年底，始發現地下室牆角有滲水問題，則甲仍得對乙主張負瑕疵擔保 責任", "若甲於A屋交付後第1年6月底，即已發現地下室牆角有滲水問題，則甲須於第2年6月底屆 滿前，行使其瑕疵擔保之各項權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00438', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲有A屋及其所座落之B地，甲僅將該A屋出售並移轉所有權予乙。不久，甲因病身亡，由其 子丙繼承，丙復將B地出售並移轉所有權予丁。下列敘述，何者正確？', '["A屋座落於B地之上，故甲不得僅將A屋出售予乙，須連同其所座落之B地一同出售", "丙雖繼承甲之財產，若未經繼承登記，仍非B地之所有人", "丙已出售並移轉B地所有權予丁，土地所有人丁得對乙請求拆屋還地", "房屋受讓人乙得於A屋之可使用年限內，對土地受讓人丁主張有租賃關係存在 20420 20520"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00439', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲有A屋1間，出賣予乙並交付之，隨後甲又立即將A屋出賣予出價更高之丙，並辦理移轉登記 完畢。下列敘述，何者錯誤？', '["乙取得A屋所有權", "丙取得A屋所有權", "乙得向甲請求損害賠償", "丙得向乙請求返還A屋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00440', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲在乙之土地上設定普通地上權，約定期間20年，甲在該地上蓋商業大樓1棟。13年後，該大 樓因甲之重大過失而焚燬。下列敘述，何者正確？', '["甲之地上權消滅", "甲之地上權期間，重新起算", "甲得請求減免租金", "甲得在原地重建大樓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00441', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲有1間合法工廠，因向乙借錢周轉而將工廠設定普通抵押權予乙，後來又緊臨工廠增設獨立倉 庫1間，當甲無法清償債務時，乙實行抵押權時，就該增建之倉庫應如何處理？', '["乙得聲請成為共有人", "乙得聲請法院併付拍賣", "乙享有法定抵押權", "乙享有法定地上權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00442', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於民法袋地通行權之敘述，何者錯誤？', '["土地與公路無適宜之聯絡，致不能為通常之使用時，除因土地所有人之任意行為所生者外，土 地所有人得通行周圍地以至公路", "有通行權人應於通行之必要範圍內，應擇其損害最少之處所及方法為之", "有通行權人必要時，得開設馬路，但對於通行地因此所受損害，應支付償金", "因土地一部轉讓而造成袋地者，得通行讓與人或受讓人之所有土地，但必須支付償金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00443', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '質權人於占有或保管質物時，應負何種注意義務？', '["善良管理人之注意義務", "一般人之注意義務", "與處理自己事務同一注意義務", "通常事變之注意義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00444', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '下列關於親權之敘述，何者正確？', '["成年在學學生仍有受扶養必要，故仍應服從父母之親權", "對於未成年子女之親權，以父母共同行使為原則", "非婚生子女經生父認領者，即應服從生父之親權", "未成年人父母雙亡者，應由同居之祖父母任親權人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00445', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲與乙訂立買賣契約後，甲受監護宣告。甲對於債務不履行是否應負責任？', '["甲無行為能力，即使在心神回復中亦毋須負擔債務不履行責任", "甲即使在心神回復中，若其監護宣告未被撤銷，對於債務不履行毋須負責", "甲若無識別能力，對於債務不履行毋須負責", "甲受監護宣告後無法享受權利與負擔義務，對於債務不履行毋須負責"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00446', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-110-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲出售其所有置放於甲之住所的A車予乙，雙方約定於締約1週後，由乙至甲之住所受領該車。 下列敘述，何者錯誤？', '["乙依約至甲處受領A車時，如甲拒絕給付，甲即負遲延責任", "乙未依約至甲處受領A車時，甲不負遲延責任", "乙未依約至甲處受領A車時，甲僅就故意或重大過失負繼續保管A車之責任", "甲所負之債務，稱為「赴償債務」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:15+00:00", "source_pdf_sha1": "8548998a4901", "answer_pdf_sha1": "fe9da9bc7b6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "201", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
